INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0, 6, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 1, 7006, 11, 7, 129911, 0.3, 0, 0);
